using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr xz = rootComp->xZConstructionPlane();
    if (!xz)
        return false;
    Ptr sketch = sketches->add(xz);
    if (!sketch)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchLines = sketchCurves->sketchLines();
    if (!sketchLines)
        return false;
    Ptr startPoint = Point3D::create(0, 0, 0);
    if (!startPoint)
        return false;
    Ptr endPoint = Point3D::create(5, 5, 0);
    if (!endPoint)
        return false;
    sketchLines->addTwoPointRectangle(startPoint, endPoint);

    // Get the profile defined by the rectangle.
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;
    Ptr prof = profs->item(0);
    if (!prof)
        return false;

    // Create an extrusion input.
    Ptr features = rootComp->features();
    if (!features)
        return false;
    Ptr extrudes = features->extrudeFeatures();
    if (!extrudes)
        return false;
    Ptr extInput = extrudes->createInput(prof, FeatureOperations::NewBodyFeatureOperation);
    if (!extInput)
        return false;

    // Define that the extent is a distance extent of 5 cm.
    Ptr distance = ValueInput::createByReal(5);
    if (!distance)
        return false;
    extInput->setDistanceExtent(false, distance);

    // Create the extrusion.
    Ptr ext = extrudes->add(extInput);
    if (!ext)
        return false;

    // Get the body created by extrusion
    Ptr bodies = ext->bodies();
    if (!bodies)
        return false;
    Ptr body = bodies->item(0);
    if (!body)
        return false;

    // Get a face of the body
    Ptr faces = body->faces();
    if (!faces)
        return false;
    Ptr face = faces->item(0);
    if (!face)
        return false;

    // Create a construction plane by offset
    Ptr planes = rootComp->constructionPlanes();
    if (!planes)
        return false;
    Ptr planeInput = planes->createInput();
    if (!planeInput)
        return false;
    Ptr offsetDistance = ValueInput::createByString("5 cm");
    if (!offsetDistance)
        return false;
    planeInput->setByOffset(face, offsetDistance);
    Ptr plane = planes->add(planeInput);
    if (!plane)
        return false;

    // Create input entities for mirror feature
    Ptr inputEntites = ObjectCollection::create();
    if (!inputEntites)
        return false;
    inputEntites->add(body);

    // Create the input for mirror feature
    Ptr mirrorFeatures = features->mirrorFeatures();
    if (!mirrorFeatures)
        return false;
    Ptr mirrorInput = mirrorFeatures->createInput(inputEntites, plane);
    if (!mirrorInput)
        return false;

    // Create the mirror feature
    Ptr mirrorFeature = mirrorFeatures->add(mirrorInput);
    if (!mirrorFeature)
        return false;

    return true;
}
